(function () {
'use strict';
function ready(fn) {
if (document.readyState !== 'loading') fn();
else document.addEventListener('DOMContentLoaded', fn);
}
function decode(s) {
try { return atob(s); } catch (_) { return ''; }
}
var EMAIL_B64 = 'aW5mb0BzdGlwZXdlYnN0dWRpby5jb20=';
var TEL_B64   = 'KzM4NTk1MzY2NTQ4NQ==';
var WA_B64    = 'Mzg1OTUzNjY1NDg1';
function formatPhone(raw) {
var m = raw.replace(/\D/g, '');
if (m.length === 12 && m.indexOf('385') === 0) {
return '+' + m.slice(0,3) + ' ' + m.slice(3,5) + ' ' + m.slice(5,8) + ' ' + m.slice(8,10) + ' ' + m.slice(10);
}
return raw;
}
ready(function () {
var EMAIL = decode(EMAIL_B64);
var TEL   = decode(TEL_B64);
var WA    = decode(WA_B64);
var TEL_PRETTY = formatPhone(TEL);
document.querySelectorAll('[data-email]').forEach(function (el) {
el.setAttribute('href', 'mailto:' + EMAIL);
var label = el.getAttribute('data-label');
if (label === 'text') {
var span = el.querySelector('[data-text]');
if (span) span.textContent = EMAIL;
else el.textContent = EMAIL;
}
});
document.querySelectorAll('[data-tel]').forEach(function (el) {
el.setAttribute('href', 'tel:' + TEL);
var label = el.getAttribute('data-label');
if (label === 'text') {
var span = el.querySelector('[data-text]');
if (span) span.textContent = TEL_PRETTY;
else el.textContent = TEL_PRETTY;
}
});
document.querySelectorAll('[data-wa]').forEach(function (el) {
var msg = el.getAttribute('data-wa-msg') || '';
var url = 'https://wa.me/' + WA + (msg ? '?text=' + encodeURIComponent(msg) : '');
el.setAttribute('href', url);
el.setAttribute('rel', 'noopener noreferrer');
});
document.querySelectorAll('[data-year]').forEach(function (el) {
el.textContent = new Date().getFullYear();
});
var nav = document.querySelector('.nav');
if (nav) {
var onScroll = function () {
if (window.scrollY > 12) nav.classList.add('nav--scrolled');
else nav.classList.remove('nav--scrolled');
};
onScroll();
window.addEventListener('scroll', onScroll, { passive: true });
}
var burger = document.getElementById('burger');
var links = document.querySelector('.nav__links');
if (burger && links) {
burger.addEventListener('click', function () {
var open = links.classList.toggle('open');
burger.setAttribute('aria-expanded', String(open));
burger.setAttribute('aria-label', open ? 'Zatvori meni' : 'Otvori meni');
document.body.classList.toggle('nav-open', open);
});
links.querySelectorAll('a').forEach(function (a) {
a.addEventListener('click', function () {
links.classList.remove('open');
burger.setAttribute('aria-expanded', 'false');
document.body.classList.remove('nav-open');
});
});
document.addEventListener('keydown', function (e) {
if (e.key === 'Escape' && links.classList.contains('open')) {
links.classList.remove('open');
burger.setAttribute('aria-expanded', 'false');
document.body.classList.remove('nav-open');
burger.focus();
}
});
}
var reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
var reveals = document.querySelectorAll('.reveal');
if (reveals.length) {
if (reduceMotion || !('IntersectionObserver' in window)) {
reveals.forEach(function (el) { el.classList.add('in'); });
} else {
var io = new IntersectionObserver(function (entries) {
entries.forEach(function (e) {
if (e.isIntersecting) { e.target.classList.add('in'); io.unobserve(e.target); }
});
}, { threshold: 0.12, rootMargin: '0px 0px -40px 0px' });
reveals.forEach(function (el) { io.observe(el); });
}
}
if (!reduceMotion && window.matchMedia('(hover:hover)').matches) {
var blobs = document.querySelectorAll('.blob');
if (blobs.length) {
var raf = 0;
window.addEventListener('mousemove', function (e) {
if (raf) return;
raf = requestAnimationFrame(function () {
var x = (e.clientX / window.innerWidth - 0.5) * 20;
var y2 = (e.clientY / window.innerHeight - 0.5) * 20;
blobs.forEach(function (b, i) {
b.style.translate = (x * (i ? -1 : 1)) + 'px ' + (y2 * (i ? -1 : 1)) + 'px';
});
raf = 0;
});
}, { passive: true });
}
}
var form = document.getElementById('contactForm');
var status = document.getElementById('formStatus');
if (form && status) {
form.addEventListener('submit', function (e) {
if (form.hasAttribute('data-netlify')) {
status.textContent = 'Šaljem poruku…';
setTimeout(function () {
status.textContent = 'Hvala! Poruka je poslana.';
form.reset();
}, 1000);
return;
}
e.preventDefault();
var data = new FormData(form);
if (data.get('website')) return;
var loaded = parseInt(form.dataset.loaded || '0', 10);
if (loaded && (Date.now() - loaded) < 2000) {
status.textContent = 'Pokušajte ponovno za nekoliko sekundi.';
return;
}
var name = String(data.get('name') || '').trim().slice(0, 100);
var email = String(data.get('email') || '').trim().slice(0, 200);
var message = String(data.get('message') || '').trim().slice(0, 2000);
if (!name || !email || !message) {
status.textContent = 'Molimo popunite sva polja.';
return;
}
if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
status.textContent = 'Neispravna e-mail adresa.';
return;
}
var body = encodeURIComponent('Ime: ' + name + '\nEmail: ' + email + '\n\n' + message);
status.textContent = 'Otvaram email klijent…';
window.location.href = 'mailto:' + EMAIL + '?subject=' + encodeURIComponent('Upit s web stranice') + '&body=' + body;
setTimeout(function () {
status.textContent = 'Hvala! Ako se email ne otvori, javite se na WhatsApp.';
form.reset();
form.dataset.loaded = String(Date.now());
}, 600);
});
form.dataset.loaded = String(Date.now());
}
var COOKIE_KEY = 'sws_cookie_consent';
var banner = document.getElementById('cookieBanner');
var accept = document.getElementById('cookieAccept');
var reject = document.getElementById('cookieReject');
var settings = document.querySelectorAll('[data-cookie-settings]');
var setConsent = function (val) {
try { localStorage.setItem(COOKIE_KEY, val); } catch (_) {}
if (banner) banner.classList.remove('show');
};
var stored = null;
try { stored = localStorage.getItem(COOKIE_KEY); } catch (_) {}
if (!stored && banner) {
setTimeout(function () { banner.classList.add('show'); }, 800);
}
if (accept) accept.addEventListener('click', function () { setConsent('accepted'); });
if (reject) reject.addEventListener('click', function () { setConsent('rejected'); });
settings.forEach(function (btn) {
btn.addEventListener('click', function (e) {
e.preventDefault();
if (banner) banner.classList.add('show');
});
});
});
})();